import type { ComponentProps } from "react";
import { forwardRef, useState } from "react";
import { get } from "../../helpers/get";
import { resolveProps } from "../../helpers/resolve-props";
import { useResolveTheme } from "../../helpers/resolve-theme";
import { twMerge } from "../../helpers/tailwind-merge";
import { useThemeProvider } from "../../theme/provider";
import type { FlowbiteBoolean, ThemingProps } from "../../types";
import type { NavbarBrandTheme } from "./NavbarBrand";
import type { NavbarCollapseTheme } from "./NavbarCollapse";
import { NavbarContext } from "./NavbarContext";
import type { NavbarLinkTheme } from "./NavbarLink";
import type { NavbarToggleThem } from "./NavbarToggle";
import { navbarTheme } from "./theme";

export interface NavbarTheme {
  root: NavbarRootTheme;
  brand: NavbarBrandTheme;
  collapse: NavbarCollapseTheme;
  link: NavbarLinkTheme;
  toggle: NavbarToggleThem;
}

export interface NavbarRootTheme {
  base: string;
  rounded: FlowbiteBoolean;
  bordered: FlowbiteBoolean;
  inner: {
    base: string;
    fluid: FlowbiteBoolean;
  };
}

export interface NavbarProps extends ComponentProps<"nav">, ThemingProps<NavbarTheme> {
  menuOpen?: boolean;
  fluid?: boolean;
  rounded?: boolean;
  border?: boolean;
}

export const Navbar = forwardRef<HTMLElement, NavbarProps>((props, ref) => {
  const provider = useThemeProvider();
  const theme = useResolveTheme(
    [navbarTheme, provider.theme?.navbar, props.theme],
    [get(provider.clearTheme, "navbar"), props.clearTheme],
    [get(provider.applyTheme, "navbar"), props.applyTheme],
  );

  const {
    border,
    children,
    className,
    fluid = false,
    menuOpen,
    rounded,
    ...restProps
  } = resolveProps(props, provider.props?.navbar);

  const [isOpen, setIsOpen] = useState(menuOpen);

  return (
    <NavbarContext.Provider
      value={{ theme: props.theme, clearTheme: props.clearTheme, applyTheme: props.applyTheme, isOpen, setIsOpen }}
    >
      <nav
        ref={ref}
        className={twMerge(
          theme.root.base,
          theme.root.bordered[border ? "on" : "off"],
          theme.root.rounded[rounded ? "on" : "off"],
          className,
        )}
        {...restProps}
      >
        <div className={twMerge(theme.root.inner.base, theme.root.inner.fluid[fluid ? "on" : "off"])}>{children}</div>
      </nav>
    </NavbarContext.Provider>
  );
});

Navbar.displayName = "Navbar";

"use client";

import { forwardRef, type ComponentProps, type ReactEventHandler, type ReactNode } from "react";
import { get } from "../../helpers/get";
import { useResolveTheme } from "../../helpers/resolve-theme";
import { twMerge } from "../../helpers/tailwind-merge";
import { useThemeProvider } from "../../theme/provider";
import type { ThemingProps } from "../../types";
import { paginationTheme } from "./theme";

export interface PaginationButtonTheme {
  base: string;
  active: string;
  disabled: string;
}

export interface PaginationButtonProps extends ComponentProps<"button">, ThemingProps<PaginationButtonTheme> {
  active?: boolean;
  children?: ReactNode;
  className?: string;
  onClick?: ReactEventHandler<HTMLButtonElement>;
}

export interface PaginationPrevButtonProps extends Omit<PaginationButtonProps, "active"> {
  disabled?: boolean;
}

export const PaginationButton = forwardRef<HTMLButtonElement, PaginationButtonProps>(
  ({ active, children, className, onClick, theme: customTheme, clearTheme, applyTheme, ...props }, ref) => {
    const provider = useThemeProvider();
    const theme = useResolveTheme(
      [paginationTheme, provider.theme?.pagination, customTheme],
      [get(provider.clearTheme, "pagination"), clearTheme],
      [get(provider.applyTheme, "pagination"), applyTheme],
    );

    return (
      <button
        ref={ref}
        type="button"
        className={twMerge(active && theme.pages.selector.active, className)}
        onClick={onClick}
        {...props}
      >
        {children}
      </button>
    );
  },
);

PaginationButton.displayName = "PaginationButton";

export function PaginationNavigation({
  children,
  className,
  onClick,
  disabled = false,
  theme: customTheme,
  clearTheme,
  applyTheme,
  ...props
}: PaginationPrevButtonProps) {
  const provider = useThemeProvider();
  const theme = useResolveTheme(
    [paginationTheme, provider.theme?.pagination, customTheme],
    [get(provider.clearTheme, "pagination"), clearTheme],
    [get(provider.applyTheme, "pagination"), applyTheme],
  );

  return (
    <button
      type="button"
      className={twMerge(disabled && theme.pages.selector.disabled, className)}
      disabled={disabled}
      onClick={onClick}
      {...props}
    >
      {children}
    </button>
  );
}

PaginationNavigation.displayName = "PaginationNavigation";

#!/usr/bin/env node

import { args, type Arg } from './utils/args'

import * as build from './commands/build'
import * as canonicalize from './commands/canonicalize'
import { help } from './commands/help'

const sharedOptions = {
  '--help': { type: 'boolean', description: 'Display usage information', alias: '-h' },
} satisfies Arg

function buildUsage(command = 'tailwindcss') {
  return `${command} [--input input.css] [--output output.css] [--watch] [options…]`
}

function rootHelp({ invalid }: { invalid?: string } = {}) {
  help({
    invalid,
    usage: [buildUsage('tailwindcss'), buildUsage('tailwindcss build'), canonicalize.usage()],
    commands: {
      build: 'Build your CSS',
      canonicalize: 'Canonicalize candidate lists',
    },
    options: { ...build.options(), ...sharedOptions },
  })
}

async function run() {
  let argv = process.argv.slice(2)
  let command = argv[0]
  let rootFlags = args({ ...build.options(), ...sharedOptions }, argv)

  if (command === 'build') {
    let flags = args({ ...build.options(), ...sharedOptions }, argv.slice(1))

    if ((process.stdout.isTTY && argv.length === 1) || flags['--help']) {
      help({
        usage: [buildUsage('tailwindcss build')],
        options: { ...build.options(), ...sharedOptions },
      })
      process.exit(0)
    }

    await build.handle(flags)
    return
  }

  if (command === 'canonicalize') {
    let result = await canonicalize.runCommandLine({ argv: argv.slice(1) })

    if (result.stdout.length > 0) {
      process.stdout.write(`${result.stdout}\n`)
    }

    if (result.stderr.length > 0) {
      process.stderr.write(`${result.stderr}\n`)
    }

    process.exitCode = result.exitCode
    return
  }

  if ((process.stdout.isTTY && command === undefined) || rootFlags['--help']) {
    rootHelp()
    process.exit(0)
  }

  if (command && !command.startsWith('-')) {
    rootHelp({ invalid: command })
    process.exit(1)
  }

  let flags = args({
    ...build.options(),
    ...sharedOptions,
  })

  await build.handle(flags)
}

await run()
